The idea behind this PR is to add an easy way to access the main activity and Java VM that are inited by Godot in gdextensions. As of now, one is forced to create a whole plugin to achieve this goal, which most of the time is quite overengineered of a solution. This PR adds a function that can be exposed by gdextensions (`request_java_ref`, although i'm not sure if the naming here must follow some speicifc standard and thus another name is more appropriate) that, when found in the symtable of a loaded so, gets automatically called with references to the JVM and the godot activity. This way a gdextension can get references to those with a code as simple as this (showcasing an example with FMOD initialization that requires such references on Android to correctly init):

```
extern "C" {
#include <jni.h>
#include <fmod_android.h>
}

static JavaVM* _jvm = nullptr;
static jobject _activity = nullptr;

extern "C" JNIEXPORT void request_java_ref(JavaVM *jvm, jobject activity) {
    _jvm = jvm;
    _activity = activity;
}

void init_fmod() {
   FMOD_Android_JNI_Init(_jvm, _activity);
}
```

**Fixes #117236**

The virtual joystick was not redrawn after changing the visibility mode.  
As a result, the joystick would not update immediately and only appeared after the user interacted with it.

```cpp
void VirtualJoystick::set_visibility_mode(VisibilityMode p_mode) {
	visibility = p_mode;
}
```

### Fix
Call the `queue_redraw()` after changing the visibility mode

```cpp
void VirtualJoystick::set_visibility_mode(VisibilityMode p_mode) {
// No need to update if visibility mode is same.
	if(visibility == p_mode){
		return;
	}
	visibility = p_mode;
	queue_redraw();
}
```

Unlike other generic containers of the core, RingBuffer has been using plain `int`s instead of `(u)int*_t`s or aliases to them. This PR attempts to modernize both the internals and the public APIs of the `RingBuffer` by using `(u)int*_t`s.

## Known issues
The changes made in this PR seem to have a performance regression but I am not sure if it stems from my benchmarking method or uints having characteristics that I don't know of. Please let me know if I there is something wrong with my method.

Edit: This regression seem to happen on GCC but not on Clang (didn't test MSVC). From what I understood from digging around the assembly is that, while GCC unrolls the loops with the `int` variant, it does not with the `uint32_t`. Clang doesn't seem to have this issue.

### Benchmark code and method
Replace `platform/linuxbsd/godot_linuxbsd.cpp` with the following and create a release build:
```cpp
#include "os_linuxbsd.h"

#include "core/profiling/profiling.h"
#include "core/templates/ring_buffer.h"
#include "main/main.h"

#ifdef _WIN32
#include <intrin.h>
#else
#include <x86intrin.h>
#endif

#include <unistd.h>
#include <climits>
#include <clocale>
#include <cstdlib>
#include <iostream>

#if defined(ASAN_ENABLED)
#include <sys/resource.h>
#endif

#if defined(__x86_64) || defined(__x86_64__)
void __cpuid(int *r_cpuinfo, int p_info) {
	// Note: Some compilers have a buggy `__cpuid` intrinsic, using inline assembly (based on LLVM-20 implementation) instead.
	__asm__ __volatile__(
			"xchgq %%rbx, %q1;"
			"cpuid;"
			"xchgq %%rbx, %q1;"
			: "=a"(r_cpuinfo[0]), "=r"(r_cpuinfo[1]), "=c"(r_cpuinfo[2]), "=d"(r_cpuinfo[3])
			: "0"(p_info));
}
#endif

// For export templates, add a section; the exporter will patch it to enclose
// the data appended to the executable (bundled PCK).
#if !defined(TOOLS_ENABLED) && defined(__GNUC__)
static const char dummy[8] __attribute__((section("pck"), used)) = { 0 };

// Dummy function to prevent LTO from discarding "pck" section.
extern "C" const char *pck_section_dummy_call() __attribute__((used));
extern "C" const char *pck_section_dummy_call() {
	return &dummy[0];
}
#endif

unsigned int _IA32_TSC_AUX;
volatile size_t volatile_size_t = 0;
[[gnu::noipa]]
__attribute__((noinline)) void black_box_write(RingBuffer<uint32_t> &set, Vector<uint32_t> &arr) {
	set.write(arr.ptr(), arr.size());
}
[[gnu::noipa]]
__attribute__((noinline)) void black_box_single_read(RingBuffer<uint32_t> &set) {
	volatile_size_t += set.read();
}
[[gnu::noipa]]
__attribute__((noinline)) void black_box_array_read(RingBuffer<uint32_t> &set, Vector<uint32_t> &arr) {
	volatile_size_t += set.read(arr.ptrw(), arr.capacity());
}
[[gnu::noipa]]
__attribute__((noinline)) void black_box_clear(RingBuffer<uint32_t> &set) {
	set.clear();
}

int main(int argc, char *argv[]) {
	int cpuinfo[4];
	constexpr int run_len = 20000;

	for (const int size : { 1, 2, 8, 64, 1024, 4096, 20000 }) {
		std::cout << "RingBuffer<uint32_t>" << size << std::endl;
		{
			size_t time_ns = 0;
			size_t time_ns1 = 0;
			for (int run = 0; run < run_len / size; run++) {
				RingBuffer<uint32_t> set = { 20 };
				Vector<uint32_t> tmp = {};
				for (int idx = 0; idx < size; idx++) {
					tmp.append(idx);
				}
				__cpuid(cpuinfo, 0);
				auto t0 = __rdtsc();
				black_box_write(set, tmp);
				auto t1 = __rdtscp(&_IA32_TSC_AUX);
				__cpuid(cpuinfo, 0);
				time_ns += t1 - t0;
			}

			std::cout << "write:" << size << std::endl;
			std::cout << time_ns << "\n";
		}
		{
			size_t time_ns = 0;
			for (int run = 0; run < run_len / size; run++) {
				RingBuffer<uint32_t> set = { 20 };
				for (int idx = 0; idx < size; idx++) {
					// Test
					set.write(idx);
				}
				for (int idx = 0; idx < size; idx++) {
					// Test
					__cpuid(cpuinfo, 0);
					auto t0 = __rdtsc();
					black_box_single_read(set);
					auto t1 = __rdtscp(&_IA32_TSC_AUX);
					__cpuid(cpuinfo, 0);
					time_ns += t1 - t0;
				}
			}

			std::cout << "single read:" << size << std::endl;
			std::cout << time_ns << "\n";
		}
		{
			size_t time_ns = 0;
			for (int run = 0; run < run_len / size; run++) {
				RingBuffer<uint32_t> set = { 20 };
				Vector<uint32_t> tmp = {};
				tmp.reserve(size);
				for (int idx = 0; idx < size; idx++) {
					set.write(idx);
				}
				__cpuid(cpuinfo, 0);
				auto t0 = __rdtsc();
				black_box_array_read(set, tmp);
				auto t1 = __rdtscp(&_IA32_TSC_AUX);
				__cpuid(cpuinfo, 0);
				time_ns += t1 - t0;
			}

			std::cout << "array read:" << size << std::endl;
			std::cout << time_ns << "\n";
		}
		{
			size_t time_ns = 0;
			for (int run = 0; run < run_len / size; run++) {
				RingBuffer<uint32_t> set = { 20 };
				for (int idx = 0; idx < size; idx++) {
					// Test
					set.write(idx);
				}
				__cpuid(cpuinfo, 0);
				auto t0 = __rdtsc();
				black_box_clear(set);
				auto t1 = __rdtscp(&_IA32_TSC_AUX);
				__cpuid(cpuinfo, 0);
				time_ns += t1 - t0;
			}

			std::cout << "clear:" << size << std::endl;
			std::cout << time_ns << "\n";
		}
	}
}
```
You can learn more about the use of `__cpuid`, `__rdtsc`, and `__rdtscp` at the [How to Benchmark Code Execution Times on Intel® IA-32 and IA-64 Instruction Set Architectures](https://cis.temple.edu/~qzeng/cis3207-spring18/files/ia-32-ia-64-benchmark-code-execution-paper.pdf) paper.

