```cs
using Godot;
using Godot.Collections;

[GlobalClass]
public partial class TestNode : Node
{
    [Export] public Array<Resource> Resources;

    public override void _Ready()
    {
        var allEntriesDict = ResourceLoader.GetCachedEntries();
        GD.Print(Json.Stringify(allEntriesDict, "\t"));
        
        var allPathsTypesDict  = ResourceLoader.GetCachedPathsInfos(ResourceLoader.FilterTarget.TypeHint);
        GD.Print(Json.Stringify(allPathsTypesDict, "\t"));
        
        var allImgPaths  = ResourceLoader.GetCachedEntriesFiltered(
            ResourceLoader.FilterTarget.TypeHint, 
            ResourceLoader.FilterComparator.Equals, 
            "Image",
            100
        );
        GD.Print(Json.Stringify(allImgPaths, "\t"));
        
        var allResPaths  = ResourceLoader.GetCachedPathsInfosFiltered(
            ResourceLoader.FilterTarget.TypeHint, 
            ResourceLoader.FilterTarget.Path, 
            ResourceLoader.FilterComparator.BeginsWith, 
            "res://new",
            100
        );
        GD.Print(Json.Stringify(allResPaths, "\t"));
    }
}
```

